import{_ as a,c as i,o as e,ah as o}from"./chunks/framework.C-x9UAyH.js";const h=JSON.parse('{"title":"Comandos para la gestión de submódulos","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"git/versionamiento/gestion_submodulos.md","filePath":"git/versionamiento/gestion_submodulos.md","lastUpdated":1735751606000}'),t={name:"git/versionamiento/gestion_submodulos.md"};function l(n,s,r,d,u,p){return e(),i("div",null,[...s[0]||(s[0]=[o('<h1 id="comandos-para-la-gestion-de-submodulos" tabindex="-1">Comandos para la gestión de submódulos <a class="header-anchor" href="#comandos-para-la-gestion-de-submodulos" aria-label="Permalink to &quot;Comandos para la gestión de submódulos&quot;">​</a></h1><p>Un submódulo en Git es un repositorio dentro de otro repositorio. Esto es útil cuando tu proyecto depende de otro proyecto que deseas gestionar por separado (por ejemplo, una librería externa).</p><div class="tip custom-block"><p class="custom-block-title">¿Qué hace?</p><ul><li><p>update: Descarga la versión correcta de cada submódulo definida en el commit actual del repositorio principal.</p></li><li><p>--init: Inicializa cualquier submódulo que aún no haya sido configurado en el repositorio. Esto crea los enlaces necesarios entre tu proyecto principal y el submódulo.</p></li><li><p>--recursive: Asegura que los submódulos dentro de otros submódulos (submódulos anidados) también sean inicializados y actualizados.</p></li></ul></div><h2 id="inicializar-actualizar-y-clonar-submodulos-dentro-de-un-repositorio" tabindex="-1">Inicializar, actualizar y clonar submódulos dentro de un repositorio <a class="header-anchor" href="#inicializar-actualizar-y-clonar-submodulos-dentro-de-un-repositorio" aria-label="Permalink to &quot;Inicializar, actualizar y clonar submódulos dentro de un repositorio&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> submodule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recursive</span></span></code></pre></div><p>Ejemplo de uso:</p><ul><li>Supongamos que clonamos un repositorio que contiene submódulos:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/usuario/proyecto-con-submodulos.git</span></span></code></pre></div><ul><li>Después de clonar, los submódulos no estarán descargados. Para inicializarlos y actualizarlos:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> submodule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recursive</span></span></code></pre></div><ul><li>Resultado:</li></ul><ul><li>Los submódulos se clonan en las rutas definidas en el repositorio principal.</li><li>Las versiones específicas de los submódulos (según el commit registrado) se actualizan automáticamente.</li></ul>',12)])])}const m=a(t,[["render",l]]);export{h as __pageData,m as default};
